js: // Initialize variables
const itemList = document.getElementById('itemList');
const loadMoreButton = document.getElementById('loadMore');
let items = [];
let currentPage = 1;
let itemsPerPage = 10;
let observer;

// Load initial items
loadInitialItems();

// Function to load initial items
function loadInitialItems() {
    fetch('/api/items?page=1&limit=10')
        .then(response => response.json())
        .then(data => {
            items = data.items;
            renderItems();
            observer = new IntersectionObserver(checkIfBottomReached, { threshold: 1 });
            observer.observe(itemList);
        });
}

// Function to render items
function renderItems() {
    itemList.innerHTML = '';
    items.forEach(item => {
        const listItem = document.createElement('li');
        listItem.textContent = item.name;
        itemList.appendChild(listItem);
    });
}

// Function to load more items
function loadMoreItems() {
    currentPage++;
    fetch('/api/items?page=' + currentPage + '&limit=' + itemsPerPage)
        .then(response => response.json())
        .then(data => {
            items = items.concat(data.items);
            renderItems();
        });
}

// Function to check if bottom is reached
function checkIfBottomReached(entries) {
    if (entries[0].isIntersecting) {
        loadMoreItems();
    }
}

// Add event listener to load more button
loadMoreButton.addEventListener('click', loadMoreItems);

